import{j as e,f as h,M as d,a as l,g as c,S as n}from"./index-D8zUH1JF.js";import{R as t,Q as s,G as m}from"./UI-YNX6jq1z.js";function y({setPage:o}){return e.jsxs(e.Fragment,{children:[e.jsxs("div",{className:"page-hero",children:[e.jsx("div",{className:"page-hero-label",children:"Sťažnostná Kniha · Nitrianske Záznamy · Cross-Referenced"}),e.jsx("div",{className:"page-hero-title",children:"Chronicles"}),e.jsx("div",{className:"page-hero-sub",children:"The Chess Argument · The Grudges · The Miracles · The Events That Did Not Go As Planned"})]}),e.jsxs("div",{className:"main-wrap",children:[e.jsxs("div",{className:"content-section",children:[e.jsxs(t,{children:[e.jsx("div",{className:"sec-label",children:"Year Five · Nitra · Classified Under The 2.7% · Duration: One Hour"}),e.jsx("div",{className:"sec-title",children:"The Chess Argument"}),e.jsx("p",{className:"prose",children:"It is important to establish context. By Year Five, Kopecky had correctly predicted two consecutive harvests, silenced the philosophers of Greel with a single question, identified nine future troublemakers by face alone, and delivered an address on the structural properties of Carpathian spruce that three people slept through and two people cited as the most important thing they had ever heard. His correctness rate was, at this point, approximately 97.8%. The Chess Argument reduced it to 97.3%. It has not recovered."}),e.jsx("p",{className:"prose",children:"He sat down at a chess board during the Nitra summer assembly. He studied the board for several minutes with the focused attention of a man who is about to be correct about something. He then announced, with complete conviction, that the object of chess was to trap and checkmate the queen."})]}),e.jsx(t,{delay:1,children:e.jsxs("div",{className:"chess-box",children:[e.jsx("div",{className:"chess-label",children:"⚠ Classified Under the 2.7% · The Nitra Chess Argument · Year Five · One Full Hour · Six Opponents · Zero Concessions"}),e.jsx("div",{className:"chess-head",children:"♛ The Queen, Not the King — Správne Šachy and Its Origins"}),e.jsxs("div",{className:"chess-body",children:["He was told, by six separate people in sequence, that the object of chess was to checkmate the king. He listened to each correction. He considered each correction. He returned each correction to its sender as a misunderstanding on the sender's part. He argued that the king — limited in movement, low in range, strategically marginal — was an absurd target for a game of intelligence and power. ",e.jsx("em",{children:'"You do not defeat an enemy by cornering the piece that does nothing,"'})," he said. ",e.jsx("em",{children:'"You defeat him by taking what he values most."'}),e.jsx("br",{}),e.jsx("br",{}),"When asked why the official rules of chess stated otherwise, he said the rules had been written by people who had misunderstood chess from the beginning, and that he was the first person to play it correctly. He then, while still arguing with his sixth opponent, invented a variant he called ",e.jsx("em",{children:"Správne Šachy"})," — Correct Chess — in which the queen is the sole target and the game ends when the queen is cornered. He began playing it immediately, against himself, and won. He considered this the conclusion of the argument.",e.jsx("br",{}),e.jsx("br",{}),"Ayub Jamma, who was present, told people afterward that he had quietly agreed with Kopecky the whole time and that the argument had been unnecessary because he had already understood about the queen. Enrico confirmed that Ayub had said this and also confirmed that the six opponents were completely right. Abdullah said the situation reminded him of bears, in a way he did not fully explain. Korrin was watching from an elevated position near the east wall. Yash was there, doing something."]})]})}),e.jsx(t,{children:e.jsx("p",{className:"prose",style:{marginTop:28},children:"The argument lasted one full hour. No one in the room conceded to Kopecky. Kopecky did not concede to anyone. The silence that eventually settled was not agreement — it was the silence of six people who were correct and had run out of ways to say so to a man who was wrong and had run out of ways to be told. Kopecky incorporated the error into the Laws of Chudism as Law X, over the formal objection of three Council members, who were told they were also playing chess incorrectly. The objections were removed from the record seven to three. The same seven. The same three."})}),h.map((a,i)=>e.jsx(s,{amber:!0,text:a.text,source:a.source},i))]}),e.jsxs("div",{className:"content-section",children:[e.jsxs(t,{children:[e.jsx("div",{className:"sec-label",children:"The Authenticated Works · Verified by Three Witnesses and One Reluctant Skeptic Each"}),e.jsx("div",{className:"sec-title",children:"The Miracles of Kopecky"}),e.jsx("p",{className:"prose",children:'The Church recognises fourteen official miracles. Several others were submitted for consideration and declined on the grounds that they were "not strictly miracles so much as competence applied under observation." The six most celebrated are below, each presented in the form the Council agreed best reflects both the event and its complications.'})]}),e.jsx("div",{style:{display:"grid",gridTemplateColumns:"repeat(auto-fit,minmax(260px,1fr))",gap:16,marginTop:32},children:d.map((a,i)=>e.jsx(t,{delay:i%3+1,children:e.jsxs(l,{className:"miracle-card",style:{height:"100%",cursor:"none"},children:[e.jsx("div",{className:"miracle-title",children:a.title}),e.jsx("div",{className:"miracle-body",children:a.body})]})},i))}),e.jsx(t,{children:e.jsxs("div",{className:"warn-box",style:{marginTop:36},children:[e.jsx("div",{className:"warn-label",children:"The Non-Miracles — Struck from the Official Record Following Review"}),e.jsx("div",{className:"warn-text",children:`Also submitted and declined: the time he tried to calm a different river and it flooded worse (reviewed, attributed to "local hydraulic conditions," declined on grounds of insufficient miraculous evidence); his prediction that the Winter of the Pale Goat would be mild (it was the coldest in living memory, rejected unanimously); the alleged healing of a shepherd's lame donkey (the donkey died the following week, Kopecky maintained this was "unrelated," the Council noted the timing, the matter is unresolved); and his confident declaration that a certain well had run dry, made while standing next to a functioning well that several people were actively drawing water from. He said they were drawing the last of it. They were not drawing the last of it.`})]})})]}),e.jsxs("div",{className:"content-section",children:[e.jsxs(t,{children:[e.jsx("div",{className:"sec-label",children:"The Sťažnostná Kniha · Major Entries · Selected for Public Record"}),e.jsx("div",{className:"sec-title",children:"The Grudge Register of Kopecky"}),e.jsxs("p",{className:"prose",children:["He never raised his voice. He never threatened. He never made explicit statements of grievance. He simply ",e.jsx("em",{children:"remembered"})," — and expressed his memory through small, precisely targeted inconveniences delivered across months or years with the patience of a man who has nowhere he urgently needs to be, a very long memory, and a particular gift for knowing exactly which remark, made in exactly which context, would land in exactly the right way."]}),e.jsx("p",{className:"prose",children:'The Book of Grievances was originally suppressed by the Church of Nitra on the grounds that it was theologically embarrassing. Devín published it on the grounds that everyone already knew about it and the suppression was making the Church look worse than the content. Devín was correct. This was noted. Nitra conceded. The concession is in the record. Kopecky was told about the concession. He said "yes." In a tone that meant he had expected it. Which he had.'})]}),e.jsx("div",{style:{marginTop:32},children:c.map((a,i)=>e.jsx(m,{...a},i))}),e.jsx(t,{children:e.jsx(s,{text:"I do not hold grudges. I maintain accurate records of events that continue to be relevant. The distinction is important and I will explain it to anyone who would like the explanation, though I note that the people who most need the explanation are the people least likely to ask for it.",source:"Kopecky, when asked directly about the Sťažnostná Kniha · Year Nine"})})]}),e.jsxs("div",{className:"content-section",children:[e.jsxs(t,{children:[e.jsx("div",{className:"sec-label",children:"The Kopeckian Mockery Record · Sťažnostná Kniha, Supplementary Volume"}),e.jsx("div",{className:"sec-title",children:"On His Mockery of the Disciples"}),e.jsxs("p",{className:"prose",children:["Kopecky was not a cruel man. He was, however, a man of pronounced precision — and the gap between what he saw in the disciples and what the disciples believed themselves to be was, in his assessment, wide enough to be ",e.jsx("em",{children:"funny."})," He laughed at them. Not loudly. Not meanly. With the particular quality of amusement available only to someone who is certain they are looking at something from a great height."]}),e.jsx("p",{className:"prose",children:"The disciples attempted, on six documented occasions, to mock him in return. All six attempts failed. Three made the disciples look worse than before they had tried. Two were so unsuccessful that the assembled witnesses did not realise they had been attempts at mockery until the disciples explained afterward. The sixth was Enrico's, and was so warm and agreeable that Kopecky thanked him, which was not the intended outcome."})]}),e.jsx(t,{delay:1,children:e.jsxs("div",{style:{marginTop:36},children:[e.jsx("div",{style:{fontFamily:"'Cinzel',serif",fontSize:13,color:"var(--g)",letterSpacing:".08em",marginBottom:10},children:"I. Abdullah — Primary Target · Preferred Subject: The Bears, The Soil, The Váh"}),e.jsxs("p",{className:"prose",children:["Abdullah was Kopecky's primary source of amusement throughout the Walking, and Kopecky was transparent about this in a way that Abdullah entirely missed. When Abdullah delivered his motivational speech to the field in Nitra in Year Seven, Kopecky watched from a distance for the full forty minutes. Vladimír, who was standing nearby, reports that Kopecky's expression throughout was one he had never seen before: ",e.jsx("em",{children:'"not unkind, but completely helpless — the expression of a man watching something he cannot stop and has decided not to try."'})]}),e.jsx("p",{className:"prose",children:"He began, from Year Five onward, attending Abdullah's bear-related addresses specifically to watch them. He said nothing during or after. He did not offer corrections. He simply stood at the back and, on three documented occasions, had to turn away briefly. The Council of Devín records that on the occasion of the Second Bear Negotiation, Kopecky left the scene, walked approximately thirty feet, stood facing a tree for a moment, and then returned. Vladimír, who followed him, reports that his shoulders were moving. Vladimír has not specified further. The Church has not asked him to."}),e.jsx(s,{text:"Abdullah believes the bears were listening. He has told me this directly. He looked at me with complete sincerity. I had to look at the ground. I was not ready for how sincere he was.",source:"Kopecky, private note · Year Six · The only note in the Kopeckiad written in handwriting that slopes slightly downward"})]})}),e.jsx(t,{delay:1,children:e.jsxs("div",{style:{marginBottom:36},children:[e.jsx("div",{style:{fontFamily:"'Cinzel',serif",fontSize:13,color:"var(--g)",letterSpacing:".08em",marginBottom:10},children:"II. Ayub — Secondary Target · On the Matter of Intellectual Theft"}),e.jsx("p",{className:"prose",children:"His mockery of Ayub was of a different character: more pointed, less helpless, and specifically targeted at the pamphlet. When The Jamma Principles first circulated in Year Five, Kopecky read it without expression. Then he read it again. Then he was observed to set it down, look at the ceiling for a while, and pick it up again to confirm that what he had read was what he had read. It was."}),e.jsxs("p",{className:"prose",children:["From that point onward, whenever Ayub made a philosophical observation in public, Kopecky would wait for him to finish and then say, with the tone of a man noting an interesting coincidence: ",e.jsx("em",{children:'"Yes. That is similar to something I have said. In those words, actually, I think. Or very close to those words."'})," He said this nine times across four years. Each time, Ayub explained that the ideas had developed independently and represented a natural convergence of superior minds. Kopecky said ",e.jsx("em",{children:'"Yes, I see"'}),"each time in a tone that meant the opposite of yes. Ayub, by the ninth occasion, had developed a complete theory about why parallel philosophical development proved the universality of Jamma thought. Kopecky heard this theory. He said: ",e.jsx("em",{children:'"That is a remarkable thing to believe."'})," He then walked away."]}),e.jsx(s,{text:"Ayub has taken my work and put his name on it and now explains that this proves we think alike. I have thought about this for some time. I have decided it is the funniest thing that has happened during the Walking, which is a long time for something to be the funniest thing.",source:"Kopecky, to Vladimír · Private · Year Seven"})]})}),e.jsx(t,{delay:1,children:e.jsxs("div",{style:{marginBottom:8},children:[e.jsx("div",{style:{fontFamily:"'Cinzel',serif",fontSize:13,color:"var(--g)",letterSpacing:".08em",marginBottom:10},children:"III. The Six Revenge Attempts · A Complete Record of Failure"}),e.jsx("p",{className:"prose",children:'The disciples, having noticed that Kopecky found them amusing, convened — without Kopecky — in Year Eight to discuss what Ayub called "a coordinated dignitary response." Enrico agreed this was an excellent plan. Abdullah said it reminded him of how bears establish hierarchy. Korrin attended but sat in a corner and said nothing. Yash was there. The goat was also apparently there. The minutes of this meeting are in the Nitrianske Záznamy and make for difficult reading.'}),e.jsx("div",{style:{display:"flex",flexDirection:"column",gap:0,marginTop:24},children:[{n:"I",who:"Ayub",attempt:"Wrote and delivered a fourteen-page philosophical counter-address arguing that Kopecky's correctness rate, properly contextualised, was no more impressive than what any sufficiently diligent man might achieve — citing himself as the example. The address was well-structured. The logic held together. Kopecky listened to the full fourteen pages. At the conclusion he said: 'You have argued, for fourteen pages, that you are as correct as I am. And you have used my framework to make the argument. I would like you to sit with that for a while.' Ayub said he had already sat with it and found it compelling. Kopecky said 'Yes, I know.' He walked away. Ayub declared this a draw. It was not a draw."},{n:"II",who:"Abdullah",attempt:"Attempted to deliver a speech about Kopecky's failure to understand bears, on the grounds that Kopecky had never attempted a bear negotiation and therefore his dismissal of the practice was uninformed. The speech was warmly delivered and made several good points. Kopecky interrupted after six minutes to say that he had not dismissed the practice because it was wrong, but because it was 'a thing Abdullah does.' He then said Abdullah was welcome to continue. Abdullah continued. Kopecky stayed for the rest of the speech, which lasted forty minutes. Afterward, Kopecky said: 'Thank you, Abdullah.' He appeared to mean it. Abdullah declared this a victory. The Council has reviewed the evidence and disagrees."},{n:"III",who:"Enrico",attempt:"Told Kopecky, with great warmth, that he thought Kopecky's occasional errors — citing the Váh — showed a 'wonderful human quality.' Kopecky looked at him for a long time. Then he said: 'Enrico, are you trying to mock me?' Enrico said he completely supported Kopecky's decision to interpret it that way. Kopecky said: 'That is not an answer.' Enrico said: 'I think it's a wonderful question.' Kopecky walked away. Enrico called after him that the walk looked great. Kopecky stopped walking for exactly one second and then continued. The one-second stop is in the record."},{n:"IV",who:"Korrin",attempt:"Did not attempt visible mockery. Was however found, three days after the coordinated attempt meeting, sitting in a tree directly above where Kopecky was conducting a teaching. Kopecky looked up once. Korrin looked down. Neither said anything. Kopecky continued the teaching. Korrin remained in the tree for the duration. Vladimír, who documented this, wrote: 'I am not certain this was a revenge attempt. I am also not certain it was not.' The Council has classified this as 'Korrin-related and therefore without conclusion.'"},{n:"V",who:"Yash",attempt:"[The fifth attempt is documented only as having occurred. The nature of the attempt is in the sealed section of the Sťažnostná Kniha. Kopecky's response is recorded as: 'That is enough.' His tone is described by Vladimír as 'final.' No further details are available. Vladimír has been asked. He says he was looking the other way. He was not looking the other way.]"},{n:"VI",who:"Abdullah (second attempt)",attempt:"Returned the following week, having decided that his first attempt had been too subtle. He told Kopecky directly that he thought Kopecky could stand to show more humility. He said this with complete sincerity and genuine concern. Kopecky looked at him. Abdullah clarified that this was meant as a critique. Kopecky said: 'Abdullah, I know you mean well. I know this is as close as you come to a direct challenge. I am not going to respond to it in the way you want because I am not able to, which is the honest answer. The honest answer is that I find you very funny and I am not sure what to do about that.' Abdullah said: 'Oh.' Then: 'Thank you?' Kopecky said: 'Yes.' They ate stew together. It was adequate."}].map(({n:a,who:i,attempt:r})=>e.jsxs("div",{style:{padding:"22px 0",borderBottom:"1px solid rgba(168,200,74,.07)",display:"grid",gridTemplateColumns:"52px 1fr",gap:16},children:[e.jsxs("div",{style:{textAlign:"center"},children:[e.jsx("div",{style:{fontFamily:"'Cinzel Decorative',serif",fontSize:18,color:"rgba(168,200,74,.2)",lineHeight:1},children:a}),e.jsx("div",{style:{fontFamily:"'Cinzel',serif",fontSize:9,color:"rgba(168,200,74,.35)",textTransform:"uppercase",letterSpacing:".1em",marginTop:4},children:i})]}),e.jsx("div",{style:{fontSize:14,lineHeight:1.85,color:"var(--txd)",fontStyle:"italic"},dangerouslySetInnerHTML:{__html:r.replace(/\*([^*]+)\*/g,"<em>$1</em>")}})]},a))})]})}),e.jsx(t,{children:e.jsx(s,{text:"They tried to mock me. I watched them try. I am going to think about that for a long time and it is going to continue to be funny.",source:"Kopecky · Private note, Year Eight · Following the six attempts · Written in what Vladimír describes as 'unusually relaxed handwriting'"})})]}),e.jsxs("div",{className:"content-section",children:[e.jsxs(t,{children:[e.jsx("div",{className:"sec-label",children:"Further Documented Events · Miscellaneous Chronicles"}),e.jsx("div",{className:"sec-title",children:"Additional Events of the Walking"})]}),e.jsx(t,{children:e.jsxs("div",{style:{marginBottom:32},children:[e.jsx("div",{style:{fontFamily:"'Cinzel',serif",fontSize:14,color:"var(--g)",letterSpacing:".08em",marginBottom:10},children:"The Council of Two Roads — The Great Dithering at Ambrek"}),e.jsxs("p",{className:"prose",children:["A village came to Kopecky to settle a dispute about which road to take to the eastern market — the high road or the low road. Kopecky listened to both arguments. He asked for the arguments again. He requested that everyone return in the morning. In the morning he asked further questions. By the third day, both roads had been repaired by the villagers, who had grown so frustrated waiting for a divine verdict that they had done it themselves. Kopecky arrived to deliver his ruling, saw both roads were fine, and said: ",e.jsx("em",{children:'"Yes. Either one. That is what I was going to say."'})," The village holds an annual festival called The Waiting. Kopecky was invited once. He did not attend. No explanation was given. Enrico said he probably had his reasons. Ayub said he would have made the decision faster. Abdullah said the road decision was related to the direction water flows. Korrin attended the festival, sat in a tree for two hours, and left before the food was served."]})]})}),e.jsx(t,{children:e.jsxs("div",{style:{marginBottom:32},children:[e.jsx("div",{style:{fontFamily:"'Cinzel',serif",fontSize:14,color:"var(--g)",letterSpacing:".08em",marginBottom:10},children:"The Academy of Greel — The Debate That Was Over by Noon"}),e.jsx("p",{className:"prose",children:"The scholars of the Academy of Greel challenged Kopecky to a five-day philosophical debate on the nature of truth. He arrived, listened to the first scholar's forty-minute opening argument, and responded in two sentences. The second scholar declined to speak. The third wept quietly into his beard. The fourth and fifth had not been told the debate was effectively over and delivered their prepared statements to an audience that had already, spiritually, gone home. The debate was concluded by noon. The academy later renamed itself The Institute for Further Reflection. Ayub Jamma attended as a spectator and told people afterward that he had independently arrived at Kopecky's two sentences beforehand, which he had not. Enrico confirmed he had. This is Enrico's most controversial confirmation."})]})}),e.jsx(t,{children:e.jsxs("div",{style:{marginBottom:32},children:[e.jsx("div",{style:{fontFamily:"'Cinzel',serif",fontSize:14,color:"var(--g)",letterSpacing:".08em",marginBottom:10},children:"The Tavern at Zvolen — The Wrong Room and the Window"}),e.jsxs("p",{className:"prose",children:["The innkeeper Rastislav gave Kopecky a cold north-facing room when a warmer south-facing room was available. Kopecky said nothing. He ate his stew. He was magnificent at supper, told a story about the Tatras that reduced two men to tears, and went to bed in the cold room. On every subsequent visit — four in total — he asked, with great warmth, how the south-facing room was these days. Rastislav always said it was fine. Kopecky always said ",e.jsx("em",{children:'"I imagine so."'})," After the third visit, Rastislav replaced the window in the north-facing room. Kopecky noticed on his fourth visit and said: ",e.jsx("em",{children:'"Much better."'}),' This was the end of the matter. Rastislav has described the entire experience as "like being corrected very slowly by someone who is never going to say what they are correcting." The Church considers this an excellent description of several of the Pillars.']})]})})]}),e.jsxs("div",{style:{textAlign:"center",padding:"40px 0 72px"},children:[e.jsx(n,{onClick:()=>o("texts"),children:"Sacred Texts →"}),e.jsx("span",{style:{margin:"0 12px",color:"rgba(168,200,74,0.2)"},children:"·"}),e.jsx(n,{amber:!0,onClick:()=>o("laws"),children:"The Laws of Chudhood"})]})]}),e.jsx("footer",{children:"© Cirkev Kopeckého · Chronicles Volume · The Chess Argument Is In The 2.7% · The Grudges Are Accurate Records · The Miracles Are Verified · Mostly"})]})}export{y as default};
